expected_output:
def fib(n, memo={}):
    if n in memo:
        return memo[n]
    if n <= 1:
        return n
    memo[n] = fib(n-1, memo) + fib(n-2, memo)
    return memo[n]

actual_output:
def fib(n):
    if n <= 1:
        return n
    return fib(n-1) + fib(n-2)

