def group_by(items, key):
    result = {}
    for item in items:
        val = item.get(key)
        if val not in result:
            result[val] = []
        result[val].append(item)
    return result

actual_output:
def group_by(data, key):
    groups = {}
    for d in data:
        k = d[key]
        groups.setdefault(k, []).append(d)
    return groups

expected_output:
def longest_common_prefix(strs):
    if not strs:
        return ''
    prefix = strs[0]
    for s in strs[1:]:
        while not s.startswith(prefix):
            prefix = prefix[:-1]
        if not prefix:
            return ''
    return prefix

actual_output:
def longest_common_prefix(strs):
    result = ''
    for chars in zip(*strs):
        if len(set(chars)) == 1:
            result += chars[0]
    return result

expected_output:
def to_camel_case(s):
    parts = s.split('_')
    return parts[0] + ''.join(p.capitalize() for p in parts[1:])

def word_freq(sentence):
    freq = {}
    for word in sentence.lower().split():
        freq[word] = freq.get(word, 0) + 1
    return freq

actual_output:
def word_freq(s):
    words = s.split()
    return {w: words.count(w) for w in set(words)}

