def rotate_right(lst, k):
    if not lst:
        return lst
    k = k % len(lst)
    return lst[-k:] + lst[:-k]

actual_output:
def rotate_right(lst, k):
    for _ in range(k):
        lst = [lst[-1]] + lst[:-1]
    return lst
